DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "PCCmacros.pl", "contextInequalitySetBuilder.pl", "parserGraphTool.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $a = random(-7, 7); InequalitySetBuilder::UseVerticalSuchThat(); Context("InequalitySetBuilder-Only"); $set_builder = Compute("{ x | x > $a}"); Context("Interval"); $interval = Compute("($a, inf)"); $gt = GraphTool("{interval,$interval}")->with( availableTools => ['IntervalTool', 'IncludeExcludePointTool'], numberLine => 1, xAxisLabel => 'x', bBox => [ -8, 8 ], ticksDistanceX => 1, minorTicksX => 0, useBracketEnds => 1, showInStatic => 0, showCoordinateHints => 0, );
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis} [ numberline, xmin=-8, xmax=8, xlabel={\(x\)}, width=0.47\orccaprintwidth, ] \addplot[openinfiniteinterval] coordinates {($a,0) (12,0)}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML Convert the given interval notation into a number line graph and set-builder notation.
[`[$interval]`]
[_]{$gt}{1}
[@KeyboardInstructions('In set-builder notation:')@]**
[_]{$set_builder}{12}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The interval notation tells us to graph all numbers between [`[$a]`] and [`\infty\text{.}`] So the shading can start at [`[$a]`] and go all the way to the right "to [`\infty`]". There should be a parenthesis at [`[$a]`] to indicate that [`[$a]`] itself is not included.
>> [@image(insertGraph($image_1), width=>600)@]* <<
We have shaded all numbers greater than [`[$a]\text{.}`] So in set-builder notation, the interval is [`[$set_builder]\text{.}`]
END_PGML_SOLUTION
